patch:
--- a/drivers/gpu/drm/i915/i915_drv.c	2015-05-06 22:04:23.000000000 +0200
+++ b/drivers/gpu/drm/i915/i915_drv.c	2015-05-12 07:17:49.920570733 +0200
@@ -622,6 +622,22 @@
 	return 0;
 }

+bool i915_hibernate_needs_quirk(struct drm_device *dev)
+{
+	switch (dev->pdev->subsystem_vendor) {
+		case 0x10cf:
+			/* Fujitsu Limited.*/
+			return (IS_GEN3(dev));
+		case PCI_VENDOR_ID_AI:
+			return (IS_GEN5(dev));
+		case PCI_VENDOR_ID_LENOVO:
+		case PCI_SUBVENDOR_ID_IBM:
+			return (INTEL_INFO(dev)->gen < 7);
+	}
+
+	return false;
+}
+
 static int i915_drm_suspend_late(struct drm_device *drm_dev, bool hibernation)
 {
 	struct drm_i915_private *dev_priv = drm_dev->dev_private;
@@ -637,15 +653,15 @@

 	pci_disable_device(drm_dev->pdev);
 	/*
-	 * During hibernation on some GEN4 platforms the BIOS may try to access
+	 * During hibernation on some platforms the BIOS may try to access
 	 * the device even though it's already in D3 and hang the machine. So
 	 * leave the device in D0 on those platforms and hope the BIOS will
 	 * power down the device properly. Platforms where this was seen:
-	 * Lenovo Thinkpad X301, X61s
+	 * Lenovo Thinkpad X301, X61s, X41, T520
+	 * FSC Lifebook S7110
+	 * Acer Aspire 1830T
 	 */
-	if (!(hibernation &&
-	      drm_dev->pdev->subsystem_vendor == PCI_VENDOR_ID_LENOVO &&
-	      INTEL_INFO(dev_priv)->gen == 4))
+	if (!(hibernation && i915_hibernate_needs_quirk(drm_dev)))
 		pci_set_power_state(drm_dev->pdev, PCI_D3hot);

 	return 0;
